def flag_data_quality_issues(df, schema):
    issues = []

    for col, expected_dtype in schema.items():
        if col not in df.columns:
            continue

        actual_dtype = str(df[col].dtype)

        # Check type mismatch
        if actual_dtype != expected_dtype:
            issues.append({
                'column': col,
                'issue_type': 'WRONG_TYPE',
                'detail': f'Expected {expected_dtype}, got {actual_dtype}'
            })

        # Check high null rate
        null_rate = df[col].isnull().mean()
        if null_rate > 0.05:
            issues.append({
                'column': col,
                'issue_type': 'HIGH_NULL_RATE',
                'detail': f'{null_rate:.1%} of values are null (threshold: 5%)'
            })

        # Check for numeric outliers
        if df[col].dtype in ['int64', 'float64']:
            col_data = df[col].dropna()
            mean = col_data.mean()
            std = col_data.std()
            if std > 0:
                max_z = ((col_data - mean) / std).abs().max()
                if max_z > 5:
                    issues.append({
                        'column': col,
                        'issue_type': 'SUSPICIOUS_OUTLIER',
                        'detail': f'Max z-score of {max_z:.1f} exceeds 5.0 threshold'
                    })

    return issues
